     1→const jwt = require('jsonwebtoken');
     2→
     3→module.exports = function authMiddleware(req, res, next) {
     4→  const header = req.headers['authorization'];
     5→  if (!header || !header.startsWith('Bearer ')) {
     6→    return res.status(401).json({ message: 'No token provided' });
     7→  }
     8→  const token = header.slice(7);
     9→  try {
    10→    const payload = jwt.verify(token, process.env.JWT_SECRET || 'cortexbuild_secret');
    11→    req.user = payload;
    12→    next();
    13→  } catch {
    14→    return res.status(401).json({ message: 'Invalid or expired token' });
    15→  }
    16→};
