   157→  uploadFile: async (file: File, options?: { project?: string; projectId?: string; category?: string }): Promise<Row> => {
   158→    const token = getToken();
   159→    const formData = new FormData();
   160→    formData.append('file', file);
   161→    if (options?.project)    formData.append('project', options.project);
   162→    if (options?.projectId)  formData.append('project_id', options.projectId);
   163→    if (options?.category)   formData.append('category', options.category);
   164→    const res = await fetch(`${API_BASE}/upload`, {
   165→      method: 'POST',
   166→      headers: token ? { Authorization: `Bearer ${token}` } : {},
   167→      body: formData,
   168→    });
   169→    if (!res.ok) throw new Error('Upload failed');
   170→    return toCamel<Row>(await res.json());
   171→  },
   172→};
