    67→// PUT /api/auth/password
    68→router.put('/password', authMiddleware, async (req, res) => {
    69→  const { currentPassword, newPassword } = req.body;
    70→  if (!currentPassword || !newPassword) return res.status(400).json({ message: 'Both passwords required' });
    71→  if (newPassword.length < 8) return res.status(400).json({ message: 'Password must be at least 8 characters' });
    72→
    73→  try {
    74→    const { rows } = await pool.query('SELECT * FROM users WHERE id = $1', [req.user.id]);
    75→    const user = rows[0];
    76→    const valid = await bcrypt.compare(currentPassword, user.password_hash);
    77→    if (!valid) return res.status(400).json({ message: 'Current password is incorrect' });
    78→
    79→    const hash = await bcrypt.hash(newPassword, 10);
    80→    await pool.query('UPDATE users SET password_hash=$1 WHERE id=$2', [hash, req.user.id]);
    81→    res.json({ message: 'Password updated successfully' });
    82→  } catch (err) {
    83→    res.status(500).json({ message: 'Server error' });
