   102→// POST /api/auth/users — create user (admin+ only)
   103→router.post('/users', authMiddleware, async (req, res) => {
   104→  if (!['super_admin','company_owner','admin'].includes(req.user.role)) {
   105→    return res.status(403).json({ message: 'Insufficient permissions' });
   106→  }
   107→
   108→  const { name, email, password, role = 'project_manager', company, phone } = req.body;
   109→  if (!name || !email || !password) return res.status(400).json({ message: 'Name, email, and password are required' });
   110→  if (password.length < 8) return res.status(400).json({ message: 'Password must be at least 8 characters' });
   111→  if (!VALID_ROLES.includes(role)) return res.status(400).json({ message: `Invalid role. Must be one of: ${VALID_ROLES.join(', ')}` });
   112→
   113→  try {
   114→    const hash = await bcrypt.hash(password, 10);
   115→    const { rows } = await pool.query(
   116→      'INSERT INTO users (name,email,password_hash,role,company,phone) VALUES ($1,$2,$3,$4,$5,$6) RETURNING id,name,email,role,company,phone,created_at',
   117→      [name, email.toLowerCase().trim(), hash, role, company || 'CortexBuild Ltd', phone || null]
   118→    );
   119→    res.status(201).json(rows[0]);
   120→  } catch (err) {
   121→    if (err.code === '23505') return res.status(409).json({ message: 'Email already in use' });
   122→    console.error('[auth/users POST]', err);
   123→    res.status(500).json({ message: 'Server error' });
   124→  }
   125→});
   126→
   127→// DELETE /api/auth/users/:id — delete user (super_admin / company_owner only)
   128→router.delete('/users/:id', authMiddleware, async (req, res) => {
   129→  if (!['super_admin','company_owner'].includes(req.user.role)) {
   130→    return res.status(403).json({ message: 'Insufficient permissions' });
   131→  }
   132→  if (req.params.id === req.user.id) return res.status(400).json({ message: 'Cannot delete your own account' });
   133→
   134→  try {
   135→    const { rowCount } = await pool.query('DELETE FROM users WHERE id = $1', [req.params.id]);
   136→    if (!rowCount) return res.status(404).json({ message: 'User not found' });
   137→    res.json({ message: 'User deleted' });
   138→  } catch (err) {
   139→    res.status(500).json({ message: 'Server error' });
   140→  }
   141→});
