    36→  const completed  = rows.filter(r => r.status === 'completed').length;
    37→  const totalBudget = rows.reduce((s, r) => s + (parseFloat(r.budget) || 0), 0);
    38→  const totalSpent  = rows.reduce((s, r) => s + (parseFloat(r.spent)  || 0), 0);
    39→
    40→  let reply = `You have **${rows.length} projects** in total — ${active} active, ${completed} completed.\n`;
