     1→const express = require('express');
     2→const multer  = require('multer');
     3→const path    = require('path');
     4→const pool    = require('../db');
     5→
     6→const router = express.Router();
     7→
     8→// ─── Multer config ────────────────────────────────────────────────────────────
     9→const ALLOWED_EXTS = ['.pdf','.doc','.docx','.xls','.xlsx','.png','.jpg','.jpeg','.dwg','.zip'];
    10→
    11→const storage = multer.diskStorage({
    12→  destination: (_req, _file, cb) => cb(null, path.join(__dirname, '../uploads')),
    13→  filename:    (_req, file, cb) => {
    14→    const unique = `${Date.now()}-${Math.round(Math.random() * 1e9)}`;
    15→    cb(null, `${unique}${path.extname(file.originalname)}`);
    16→  },
    17→});
    18→
    19→const fileFilter = (_req, file, cb) => {
    20→  const ext = path.extname(file.originalname).toLowerCase();
    21→  if (ALLOWED_EXTS.includes(ext)) cb(null, true);
    22→  else cb(new Error(`File type not allowed: ${ext}`), false);
    23→};
    24→
    25→const upload = multer({
    26→  storage,
    27→  fileFilter,
    28→  limits: { fileSize: 50 * 1024 * 1024 }, // 50 MB
    29→});
    30→
    31→// ─── Format bytes ─────────────────────────────────────────────────────────────
    32→function formatSize(bytes) {
    33→  if (bytes < 1024)           return `${bytes} B`;
    34→  if (bytes < 1024 * 1024)    return `${(bytes / 1024).toFixed(1)} KB`;
    35→  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
    36→}
    37→
    38→// ─── POST /api/upload ─────────────────────────────────────────────────────────
    39→router.post('/', upload.single('file'), async (req, res) => {
    40→  try {
    41→    if (!req.file) return res.status(400).json({ message: 'No file provided' });
    42→
    43→    const ext      = path.extname(req.file.originalname).replace('.', '').toUpperCase();
    44→    const fileSize = formatSize(req.file.size);
    45→    const name     = req.file.originalname;
    46→    const uploadedBy = req.user?.name || req.user?.email || 'Unknown';
    47→    const category = req.body.category || 'REPORTS';
    48→    const project  = req.body.project  || null;
    49→    const projectId = req.body.project_id || null;
    50→
    51→    const { rows } = await pool.query(
    52→      `INSERT INTO documents (name, type, project_id, project, uploaded_by, version, size, status, category)
    53→       VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)
    54→       RETURNING *`,
    55→      [name, ext, projectId, project, uploadedBy, '1.0', fileSize, 'current', category]
    56→    );
    57→
    58→    res.status(201).json(rows[0]);
    59→  } catch (err) {
    60→    console.error('[POST /api/upload]', err.message);
    61→    // multer file-type error comes through here when fileFilter calls cb(err)
    62→    if (err.message && err.message.startsWith('File type not allowed')) {
    63→      return res.status(400).json({ message: err.message });
    64→    }
    65→    res.status(500).json({ message: err.message });
    66→  }
    67→});
    68→
    69→// ─── Multer error handler ─────────────────────────────────────────────────────
    70→router.use((err, _req, res, _next) => {
    71→  if (err instanceof multer.MulterError) {
    72→    return res.status(400).json({ message: `Upload error: ${err.message}` });
    73→  }
    74→  res.status(500).json({ message: err.message });
    75→});
    76→
    77→module.exports = router;
    78→

